#!/usr/bin/env python3
"""NOAA APT pass scheduler.

Computes upcoming visible passes of NOAA-15/18/19 from a ground station
and emits machine-readable info so the resolver can wake up just-in-time.

Subcommands:
  next       Next pass meeting --min-elev. One line:
               EPOCH_S NAME FREQ_HZ DUR_S MAX_EL_DEG
  active     If a pass is currently in progress, print its line; otherwise
             exit 1.
  list       Human-readable list of upcoming passes (next --hours).

TLEs are cached at $AEON_NOAA_TLE_DIR (default /tmp/noaa_tles) and refreshed
from Celestrak every --tle-max-age hours.
"""

from __future__ import annotations

import argparse
import datetime as dt
import math
import os
import sys
import urllib.request
from pathlib import Path

from sgp4.api import Satrec, jday  # type: ignore[import-untyped]

SATS = [
    ("NOAA-15", 137_620_000, 25338),
    ("NOAA-18", 137_912_500, 28654),
    ("NOAA-19", 137_100_000, 33591),
]
TLE_URL = "https://celestrak.org/NORAD/elements/gp.php?CATNR={catnr}&FORMAT=tle"


def utcnow() -> dt.datetime:
    return dt.datetime.now(dt.timezone.utc).replace(tzinfo=None)


def fetch_tle(catnr: int, dest: Path) -> None:
    req = urllib.request.Request(
        TLE_URL.format(catnr=catnr),
        headers={"User-Agent": "aeon-noaa-pass-schedule/1.0"},
    )
    with urllib.request.urlopen(req, timeout=15) as r:
        data = r.read()
    dest.write_bytes(data)


def load_satrec(catnr: int, name: str, tle_dir: Path, max_age_h: float) -> Satrec:
    dest = tle_dir / f"{catnr}.tle"
    needs_refresh = True
    if dest.exists():
        age_h = (utcnow().timestamp() - dest.stat().st_mtime) / 3600.0
        if age_h < max_age_h:
            needs_refresh = False
    if needs_refresh:
        try:
            fetch_tle(catnr, dest)
        except Exception as e:
            if not dest.exists():
                raise SystemExit(f"failed to fetch TLE for {name} ({catnr}): {e}")
            print(f"warn: TLE refresh for {name} failed; using cached: {e}", file=sys.stderr)
    lines = [ln.strip() for ln in dest.read_text().splitlines() if ln.strip()]
    if len(lines) < 3:
        raise SystemExit(f"malformed TLE at {dest}")
    return Satrec.twoline2rv(lines[1], lines[2])


def gmst_rad(jd: float) -> float:
    """Greenwich Mean Sidereal Time in radians (IAU 1982 polynomial)."""
    t = (jd - 2451545.0) / 36525.0
    g = (
        280.46061837
        + 360.98564736629 * (jd - 2451545.0)
        + t * t * (0.000387933 - t / 38710000.0)
    )
    return math.radians(g % 360.0)


def eci_to_topo(
    r_eci_km: tuple[float, float, float],
    jd_utc: float,
    lat_deg: float,
    lon_deg: float,
    alt_m: float,
) -> tuple[float, float, float]:
    """Return (elevation_deg, azimuth_deg, range_km) of the satellite."""
    lat = math.radians(lat_deg)
    lon = math.radians(lon_deg)
    g = gmst_rad(jd_utc) + lon
    x, y, z = r_eci_km
    # ECI → ECEF (rotate by -gmst about z), then translate to observer
    cosg, sing = math.cos(gmst_rad(jd_utc)), math.sin(gmst_rad(jd_utc))
    xe = cosg * x + sing * y
    ye = -sing * x + cosg * y
    ze = z
    r_e = 6378.137 + alt_m / 1000.0
    sl, cl = math.sin(lat), math.cos(lat)
    so, co = math.sin(lon), math.cos(lon)
    ox = r_e * cl * co
    oy = r_e * cl * so
    oz = r_e * sl
    rx, ry, rz = xe - ox, ye - oy, ze - oz
    east = -so * rx + co * ry
    north = -sl * co * rx - sl * so * ry + cl * rz
    up = cl * co * rx + cl * so * ry + sl * rz
    rng = math.sqrt(east * east + north * north + up * up)
    el = math.degrees(math.asin(up / rng))
    az = math.degrees(math.atan2(east, north)) % 360.0
    _ = g  # silence linter; lon already folded in via az frame
    return el, az, rng


def find_passes(
    sat: Satrec,
    lat: float,
    lon: float,
    alt_m: float,
    start: dt.datetime,
    horizon_hours: float,
    coarse_step_s: int = 20,
    min_elev: float = 0.0,
) -> list[dict]:
    """Return passes [{start, end, max_el, max_t}] above min_elev."""
    end = start + dt.timedelta(hours=horizon_hours)
    t = start
    passes: list[dict] = []
    in_pass = False
    p_start = None
    p_max_el = -90.0
    p_max_t = None
    p_above_min = False
    while t < end:
        jd, fr = jday(t.year, t.month, t.day, t.hour, t.minute, t.second + t.microsecond / 1e6)
        e, r, _v = sat.sgp4(jd, fr)
        if e == 0:
            el, _az, _rng = eci_to_topo(r, jd + fr, lat, lon, alt_m)
            if el > 0:
                if not in_pass:
                    in_pass = True
                    p_start = t
                    p_max_el = el
                    p_max_t = t
                    p_above_min = el >= min_elev
                else:
                    if el > p_max_el:
                        p_max_el = el
                        p_max_t = t
                    if el >= min_elev:
                        p_above_min = True
            else:
                if in_pass:
                    if p_above_min:
                        passes.append(
                            {"start": p_start, "end": t, "max_el": p_max_el, "max_t": p_max_t}
                        )
                    in_pass = False
                    p_start = None
                    p_max_el = -90.0
                    p_max_t = None
                    p_above_min = False
        t += dt.timedelta(seconds=coarse_step_s)
    if in_pass and p_above_min and p_start is not None:
        passes.append({"start": p_start, "end": t, "max_el": p_max_el, "max_t": p_max_t})
    return passes


def collect_passes(args: argparse.Namespace, horizon_hours: float) -> list[dict]:
    tle_dir = Path(args.tle_dir)
    tle_dir.mkdir(parents=True, exist_ok=True)
    out: list[dict] = []
    now = utcnow()
    for name, freq_hz, catnr in SATS:
        sat = load_satrec(catnr, name, tle_dir, args.tle_max_age)
        for p in find_passes(
            sat,
            args.lat,
            args.lon,
            args.alt,
            now,
            horizon_hours,
            min_elev=args.min_elev,
        ):
            out.append({**p, "name": name, "freq_hz": freq_hz})
    out.sort(key=lambda p: p["start"])
    return out


def fmt_line(p: dict) -> str:
    epoch = int(p["start"].replace(tzinfo=dt.timezone.utc).timestamp())
    dur = int((p["end"] - p["start"]).total_seconds())
    return f'{epoch} {p["name"]} {p["freq_hz"]} {dur} {p["max_el"]:.1f}'


def cmd_next(args: argparse.Namespace) -> int:
    passes = collect_passes(args, args.horizon_hours)
    if not passes:
        print(
            f"no passes ≥{args.min_elev}° in next {args.horizon_hours}h", file=sys.stderr
        )
        return 1
    print(fmt_line(passes[0]))
    return 0


def cmd_active(args: argparse.Namespace) -> int:
    now = utcnow()
    passes = collect_passes(args, max(1.0, args.horizon_hours))
    for p in passes:
        if p["start"] <= now <= p["end"]:
            # Adjust the printed start to "now" so the caller's wait math is 0.
            adj = dict(p)
            adj["start"] = now
            adj["end"] = p["end"]
            print(fmt_line(adj))
            return 0
    return 1


def cmd_list(args: argparse.Namespace) -> int:
    passes = collect_passes(args, args.horizon_hours)
    print(
        f"observer: {args.lat:.4f}, {args.lon:.4f}  utc_now={utcnow():%Y-%m-%d %H:%M:%SZ}  "
        f"min_elev={args.min_elev}°"
    )
    print(
        f'{"sat":8} {"freq_MHz":10} {"start UTC":20} {"dur_min":>7} {"max_el":>7} {"start local":20}'
    )
    for p in passes[: args.limit]:
        dur = (p["end"] - p["start"]).total_seconds() / 60.0
        local = (p["start"] - dt.timedelta(seconds=args.local_offset_s)).strftime(
            "%Y-%m-%d %H:%M:%S"
        )
        print(
            f'{p["name"]:8} {p["freq_hz"]/1e6:10.4f} {p["start"]:%Y-%m-%d %H:%M:%SZ} '
            f"{dur:7.1f} {p['max_el']:7.1f}  {local}"
        )
    return 0


def env_float(name: str, default: float | None) -> float | None:
    v = os.environ.get(name)
    if v is None or v == "":
        return default
    return float(v)


def main(argv: list[str] | None = None) -> int:
    p = argparse.ArgumentParser(description=__doc__)
    p.add_argument("--lat", type=float, default=env_float("AEON_NOAA_LAT", None))
    p.add_argument("--lon", type=float, default=env_float("AEON_NOAA_LON", None))
    p.add_argument("--alt", type=float, default=env_float("AEON_NOAA_ALT_M", 50.0))
    p.add_argument(
        "--min-elev",
        type=float,
        default=env_float("AEON_NOAA_MIN_ELEV", 25.0),
        help="reject passes whose maximum elevation is below this (degrees)",
    )
    p.add_argument(
        "--horizon-hours",
        type=float,
        default=env_float("AEON_NOAA_HORIZON_HOURS", 24.0),
    )
    p.add_argument(
        "--tle-dir",
        default=os.environ.get("AEON_NOAA_TLE_DIR", "/tmp/noaa_tles"),
    )
    p.add_argument(
        "--tle-max-age",
        type=float,
        default=env_float("AEON_NOAA_TLE_MAX_AGE_H", 12.0),
    )
    p.add_argument("--limit", type=int, default=10, help="(list) max rows to print")
    p.add_argument(
        "--local-offset-s",
        type=int,
        default=int(env_float("AEON_NOAA_LOCAL_OFFSET_S", 7 * 3600) or 0),
        help="(list) seconds to subtract from UTC for the 'start local' column",
    )
    sub = p.add_subparsers(dest="cmd", required=True)
    sub.add_parser("next", help="print next pass line")
    sub.add_parser("active", help="print current pass line if one is in progress")
    sub.add_parser("list", help="human-readable schedule")
    args = p.parse_args(argv)

    if args.lat is None or args.lon is None:
        raise SystemExit(
            "lat/lon required (set --lat/--lon or AEON_NOAA_LAT/AEON_NOAA_LON env vars)"
        )

    return {"next": cmd_next, "active": cmd_active, "list": cmd_list}[args.cmd](args)


if __name__ == "__main__":
    sys.exit(main())
